/**
 * MIA-SADM — Extreme Minimal Decoder
 * Version: Canonical Output v1.3.3 (LOCKED — Prompt STRING-PACKED aligned)
 * Mode: Run Once for All Items
 *
 * Changes (minimal, format-alignment):
 * - src.ocr now: LANG|CONF|MATCH|MISMATCH_FIELDS (4)
 * - src.a   now: TYPE|DATE|TIME|LEAVE_TYPE|LEAVE_DAYS|LEAVE_HOURS_START|LEAVE_HOURS_END|LEAVE_START_DATE|LEAVE_END_DATE (9)
 * - lang enum accepts: pt | en | es | xx
 * - keep canonical output structure; set ocr.status/engine to "" (not provided in packed format)
 * - add leave.hours_start / leave.hours_end (new)
 * - keep leave.hours integer as 0 (not provided explicitly)
 */

// ---------------- Helpers ----------------
function splitSafe(value, sep, size) {
  const arr = (value || "").split(sep);
  while (arr.length < size) arr.push("");
  return arr;
}
const f = v => isNaN(parseFloat(v)) ? 0.0 : parseFloat(v);
const i = v => isNaN(parseInt(v, 10)) ? 0 : parseInt(v, 10);
const b = v => v === "1";

// ---------------- Deterministic Normalizers ----------------
function normLangPacked(lang) {
  // STRING-PACKED spec: pt | en | es | xx
  const s = (lang || "").trim().toLowerCase();
  if (s === "pt" || s === "en" || s === "es" || s === "xx") return s;
  // tolerate legacy variants without breaking
  if (s === "pt-br" || s === "pt_br" || s === "por") return "pt";
  if (s === "eng") return "en";
  if (s === "spa") return "es";
  return "xx";
}

function normCrmUF(uf) {
  const s = (uf || "").trim();
  // STRING-PACKED allows "undefined" token; preserve as empty in canonical output
  if (s.toLowerCase() === "undefined") return "";
  return /^[A-Z]{2}$/.test(s) ? s : "";
}

function normDocType(t) {
  const s = (t || "").trim();
  // STRING-PACKED allows "undefined"
  return s.toLowerCase() === "undefined" ? "" : s;
}

function clampFa(v) {
  const s = (v || "").toLowerCase();
  return ["none", "weak", "moderate", "strong"].includes(s) ? s : "none";
}

// ---------------- Date Helpers ----------------
function daysBetween(dateStr) {
  if (!dateStr) return null;
  // input is DD/MM/YYYY per prompt; JS Date() won't parse reliably.
  // Minimal safe parse for DD/MM/YYYY:
  const m = String(dateStr).match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (!m) return null;
  const dd = parseInt(m[1], 10), mm = parseInt(m[2], 10), yyyy = parseInt(m[3], 10);
  const d = new Date(Date.UTC(yyyy, mm - 1, dd));
  if (isNaN(d.getTime())) return null;
  const now = new Date();
  const nowUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));
  return Math.floor((nowUtc - d) / (1000 * 60 * 60 * 24));
}

function attendanceDateStatus(attDate) {
  const diff = daysBetween(attDate);
  if (diff === null) return "unknown";
  if (diff <= 30) return "within_deadline";
  if (diff <= 60) return "out_of_deadline";
  if (diff <= 90) return "deadline_exceeded";
  return "old_document";
}

function leaveDaysRisk(days) {
  if (days < 0) return "none";
  if (days <= 5) return "very_low";
  if (days <= 10) return "low";
  if (days <= 12) return "moderate";
  if (days <= 15) return "high";
  return "very_high";
}

function isTimeHHMM(t) {
  return /^([01]\d|2[0-3]):[0-5]\d$/.test((t || "").trim());
}

// ---------------- Input ----------------
const input = $input.first().json;

// ---------------- Find EXTREME JSON ----------------
// robust: take first "{" ... last "}" even if extra chars exist
function findJsonString(obj) {
  if (!obj) return null;

  if (typeof obj === "string") {
    const s = obj.trim();
    const start = s.indexOf("{");
    const end = s.lastIndexOf("}");
    if (start === -1 || end === -1 || end <= start) return null;
    return s.slice(start, end + 1);
  }

  if (Array.isArray(obj)) {
    for (const v of obj) {
      const found = findJsonString(v);
      if (found) return found;
    }
  }

  if (typeof obj === "object") {
    for (const k of Object.keys(obj)) {
      const found = findJsonString(obj[k]);
      if (found) return found;
    }
  }

  return null;
}

const raw = findJsonString(input);
if (!raw) throw new Error("No EXTREME JSON found");

let src;
try {
  src = JSON.parse(raw);
} catch (e) {
  throw new Error("Invalid EXTREME JSON: " + (e && e.message ? e.message : "parse_error"));
}

// ---------------- Maps ----------------
const docTypeMap = { mc: "medical_certificate", ot: "other" };
const attTypeMap = { c: "consultation", e: "exam", p: "companion", h: "hospitalization", u: "" };
const manipulationMap = { B: "blur", W: "white_patch", O: "obfuscation", T: "texture_inconsistency" };

// ---------------- Decode primitives ----------------
const [patientName, patientDocValue, patientDocTypeRaw] = splitSafe(src.p, "|", 3);
const patientDocType = normDocType(patientDocTypeRaw);

let [doctorName, crmNumber, crmState, rqeNumber] = splitSafe(src.d, "|", 4);
crmState = normCrmUF(crmState);

const [issuerName, issuerCity, issuerState, issuerCnpj] = splitSafe(src.i, "|", 4);

// a (NEW): TYPE|DATE|TIME|LEAVE_TYPE|LEAVE_DAYS|LEAVE_HOURS_START|LEAVE_HOURS_END|LEAVE_START_DATE|LEAVE_END_DATE
const [
  attType,
  attDate,
  attTime,
  leaveTypeRaw,
  leaveDays,
  leaveHoursStart,
  leaveHoursEnd,
  leaveStartDate,
  leaveEndDate
] = splitSafe(src.a, "|", 9);

const leaveType = (leaveTypeRaw || "").trim().toLowerCase(); // days | hours | indefinite | undefined

const [cidVerRaw, cidParent, cidChild] = splitSafe(src.cid, "|", 3);
const [capType, capDevice, capNotes] = splitSafe(src.cap, "|", 3);

// ocr (NEW): LANG|CONF|MATCH|MISMATCH_FIELDS
let [ocrLangRaw, ocrConf, ocrMatch, ocrMismatch] = splitSafe(src.ocr, "|", 4);
const ocrLang = normLangPacked(ocrLangRaw);

const ocrText = src.ocr_text || "";

const deArr = splitSafe(src.de, "|", 12).map(b);

let [faStatus, faDigital, faPhysical, faAI, lowRes, blur, noise, occlusion, faNotes] =
  splitSafe(src.fa, "|", 9);

faDigital = clampFa(faDigital);
faPhysical = clampFa(faPhysical);

const [qrPresent, qrReadableVisual, qrNotes] = splitSafe(src.qr, "|", 3);

// ---------------- Stamp & Signature Validity ----------------
const hasStamp = deArr[3];
const hasSignature = deArr[4];

const degraded =
  faDigital === "strong" ||
  faPhysical === "strong" ||
  b(blur) ||
  b(lowRes);

const stampValid = hasStamp && !degraded;
const signatureValid = hasSignature && !degraded;

// ---------------- Derived ----------------
const leaveDaysInt = i(leaveDays);

// packed format provides start/end times, not integer hours; keep integer hours as 0 in canonical output
const hoursStartOk = isTimeHHMM(leaveHoursStart) ? leaveHoursStart.trim() : "";
const hoursEndOk = isTimeHHMM(leaveHoursEnd) ? leaveHoursEnd.trim() : "";



const attendanceDateStatusValue = attendanceDateStatus(attDate);

// periodo_indefinido: keep previous semantics; now hours is inferred by presence of time range
const periodoIndefinidoValor =
  (leaveType === "days" && leaveDaysInt > 0) ||
  (leaveType === "hours" && (hoursStartOk || hoursEndOk)) ||
  (leaveType === "indefinite")
    ? "N"
    : "S";

// ---------------- Leave Temporal Intelligence (Deterministic) ----------------

// Helper: parse DD/MM/YYYY safely
function parseDMY(dmy) {
  const m = String(dmy || "").match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (!m) return null;
  const d = new Date(Date.UTC(+m[3], +m[2] - 1, +m[1]));
  return isNaN(d.getTime()) ? null : d;
}

// Helper: format Date -> DD/MM/YYYY
function formatDMY(d) {
  const dd = String(d.getUTCDate()).padStart(2, "0");
  const mm = String(d.getUTCMonth() + 1).padStart(2, "0");
  const yy = d.getUTCFullYear();
  return `${dd}/${mm}/${yy}`;
}

// Helper: parse HH:MM to minutes
function timeToMinutes(t) {
  if (!isTimeHHMM(t)) return null;
  const [h, m] = t.split(":").map(Number);
  return h * 60 + m;
}

// Helper: minutes to hours (ceil)
function minutesToHoursCeil(mins) {
  return mins > 0 ? Math.ceil(mins / 60) : 0;
}

// Base dates
const attDateObj = parseDMY(attDate);

// Mutable derived values
let finalStartDate = leaveStartDate || "";
let finalEndDate = leaveEndDate || "";
let finalLeaveDays = leaveDaysInt;
let finalLeaveHours = 0;
let finalAttendanceTime = attTime || "";

// ---- RULE 1: HOURS → start_date and end_date MUST be present
if (leaveType === "hours" && attDateObj) {
  if (!finalStartDate) finalStartDate = formatDMY(attDateObj);
  if (!finalEndDate) finalEndDate = formatDMY(attDateObj);
}

// ---- RULE 2: DAYS → start_date and end_date MUST be present
if (leaveType === "days" && attDateObj) {

  // If days present but dates missing → derive dates
  if (finalLeaveDays > 0 && (!finalStartDate || !finalEndDate)) {
    finalStartDate = formatDMY(attDateObj);
    const end = new Date(attDateObj);
    end.setUTCDate(end.getUTCDate() + finalLeaveDays);
    finalEndDate = formatDMY(end);
  }

  // If dates present but days missing → calculate days
  if (finalLeaveDays === 0 && finalStartDate && finalEndDate) {
    const s = parseDMY(finalStartDate);
    const e = parseDMY(finalEndDate);
    if (s && e && e >= s) {
      const diffDays = Math.ceil((e - s) / (1000 * 60 * 60 * 24));
      finalLeaveDays = diffDays;
    }
  }
}

// ---- RULE 3: HOURS → calculate quantity if missing
if (leaveType === "hours" && finalLeaveHours === 0 && hoursStartOk && hoursEndOk) {
  const startMin = timeToMinutes(hoursStartOk);
  const endMin = timeToMinutes(hoursEndOk);
  if (startMin !== null && endMin !== null && endMin > startMin) {
    finalLeaveHours = minutesToHoursCeil(endMin - startMin);
  }
}

// ---- RULE 4: HOURS → fill attendance_time if empty
if (leaveType === "hours" && !finalAttendanceTime && hoursStartOk) {
  finalAttendanceTime = hoursStartOk;
}

const leaveDaysRiskValue = leaveDaysRisk(finalLeaveDays);

// ---------------- Manipulation FAIL-SAFE ----------------
const mParts = splitSafe(src.m, "|", 4);
const mDetectedRaw = mParts[0] === "1";
const mappedTypes = (mParts[1] || "")
  .split("+")
  .map(t => manipulationMap[t])
  .filter(Boolean);

const manipulationDetected = mDetectedRaw && mappedTypes.length > 0;
const manipulationConfidence = manipulationDetected ? f(mParts[3]) : 0.0;
const impactedFields = manipulationDetected
  ? (mParts[2] || "").split("+").filter(Boolean)
  : [];

// ---------------- Build Canonical Output ----------------
const output = {
  document_metadata: {
    document_type: docTypeMap[src.t] || "other",
    is_medical_certificate: src.t === "mc",
    analysis_timestamp: new Date().toISOString()
  },

  capture: {
    capture_type: capType || "",
    device_info: capDevice || "",
    capture_quality_notes: capNotes || ""
  },

  ocr: {
    // packed format does not provide status/engine; keep empty for canonical output
    status: "",
    engine: "",
    language_detected: ocrLang || "xx",
    confidence_avg: f(ocrConf),
    match_score: f(ocrMatch),
    mismatch_fields: (ocrMismatch || "").split("+").filter(Boolean),
    full_text: ocrText
  },

  patient_identification: {
    patient_name: patientName || "",
    patient_document_type: patientDocType || "",
    patient_document_value: patientDocValue || ""
  },

  medical_professional: {
    doctor_name: doctorName || "",
    crm_number: crmNumber || "",
    crm_state: crmState || "",
    specialty_registration: rqeNumber || ""
  },

  issuer_information: {
    issuer_name: issuerName || "",
    city: issuerCity || "",
    state: issuerState || "",
    cnpj: issuerCnpj || ""
  },

  attendance_information: {
    attendance_type: attTypeMap[attType] || "",
    attendance_date: attDate || "",
    attendance_time: finalAttendanceTime,
    attendance_date_status: attendanceDateStatusValue,
    periodo_indefinido: periodoIndefinidoValor,
    leave: {
      type: leaveType || "",
      days: finalLeaveDays,
      hours: finalLeaveHours,
      hours_start: hoursStartOk,
      hours_end: hoursEndOk,
      start_date: finalStartDate,
      end_date: finalEndDate,
      leave_days_risk: leaveDaysRiskValue
    }
  },

  medical_classification: {
    cid_version:
      cidVerRaw === "CID10" ? "CID-10" :
      cidVerRaw === "CID11" ? "CID-11" : "",
    cid_parent: cidParent || "",
    cid_child: cidChild || ""
  },

  document_elements: {
    has_logo: deArr[0],
    has_letterhead: deArr[1],
    has_mandatory_fields: deArr[2],
    has_stamp: hasStamp,
    has_signature: hasSignature,
    stamp_valid: stampValid,
    signature_valid: signatureValid,
    has_disclaimer: deArr[5],
    has_issuer_data: deArr[6],
    has_doctor_data: deArr[7],
    has_patient_data: deArr[8],
    has_attendance_data: deArr[9],
    has_disease_data: deArr[10],
    has_locality_data: deArr[11]
  },

  forensic_analysis: {
    status: faStatus || "complete",
    digital_manipulation_indicators: faDigital,
    physical_manipulation_indicators: faPhysical,
    ai_generation_or_reconstruction_indicators: faAI || "none",
    visual_quality_issues: {
      low_resolution: b(lowRes),
      blur: b(blur),
      noise: b(noise),
      occlusion: b(occlusion)
    },
    forensic_notes: faNotes || ""
  },

  qr_validation: {
    qr_present_ia_detected: b(qrPresent),
    qr_readable_visual_opinion: b(qrReadableVisual),
    qr_notes: qrNotes || ""
  },

  manipulation_analysis: {
    detected: manipulationDetected,
    manipulation_types: mappedTypes,
    impacted_fields: impactedFields,
    confidence: manipulationConfidence
  },

  image_scores: {
    consistency: f(splitSafe(src.s, "|", 3)[0]),
    completeness: f(splitSafe(src.s, "|", 3)[1]),
    image_quality: f(splitSafe(src.s, "|", 3)[2])
  },

  preliminary_recommendation: {
    visual_risk: splitSafe(src.r, "|", 3)[0] || "",
    recommended_action: splitSafe(src.r, "|", 3)[1] || "",
    reason_code: splitSafe(src.r, "|", 3)[2] || ""
  }
};

// ---------------- Return ----------------
return [{ json: output }];

/**
 * n8n Code Node (JavaScript)
 * CRM Matching with Fuzzy Name Scoring
 */

// ---------------------- Helpers ----------------------

function normalizeName(name) {
  return (name || "")
    .toUpperCase()
    .replace(/\b(DR|DRA|DR\.)\b/g, "")
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[^A-Z\s]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function tokenize(name) {
  return normalizeName(name).split(" ").filter(Boolean);
}

/**
 * Name similarity score ∈ [0,1]
 * Strong weight on surname match
 */
function nameSimilarity(a, b) {
  const ta = tokenize(a);
  const tb = tokenize(b);

  if (!ta.length || !tb.length) return 0;

  const setA = new Set(ta);
  const setB = new Set(tb);

  const intersection = [...setA].filter(t => setB.has(t));
  const surnameA = ta[ta.length - 1];
  const surnameB = tb[tb.length - 1];

  let score = 0;

  // Surname weight
  if (surnameA === surnameB) score += 0.5;

  // Other tokens
  const common = intersection.length - (surnameA === surnameB ? 1 : 0);
  score += Math.min(common * 0.15, 0.45);

  return Math.min(score, 1);
}

// ---------------------- Input ----------------------

const input = $input.first().json;

const registros = input.dados || [];
const target = {
  doctor_name: $('Output Analise Imagem').first().json.medical_professional.doctor_name,
  crm_state: ( $('Output Analise Imagem').first().json.medical_professional.crm_state || "").toUpperCase()
};

// ---------------------- Matching Logic ----------------------

const THRESHOLD = 0.25;
let bestMatch = null;
let bestScore = 0;

for (const r of registros) {
  // Strong UF filter (if provided)
  if (target.crm_state && r.SG_UF !== target.crm_state) {
    continue;
  }

  const score = nameSimilarity(r.NM_MEDICO, target.doctor_name);

  if (score >= THRESHOLD && score > bestScore) {
    bestScore = score;
    bestMatch = r;
  }
}

// ---------------------- Output ----------------------

if (!bestMatch) {
  return [{
    json: {
      cfm_data: {},
      match_status: "not_found"
    }
  }];
}

return [{
  json: {
    cfm_data: {
      doctor_name: bestMatch.NM_MEDICO,
      crm_state: bestMatch.SG_UF,
      situation: bestMatch.COD_SITUACAO === "A" ? "Active" : "Inactive",
      specialty_registration: bestMatch.ESPECIALIDADE,
    match_status: "matched",
    match_score: Number(bestScore.toFixed(3))
    }
  }
}];

// n8n Code / Function Node
// Input: WHO ICD API JSON (single item)

const input = $input.first().json;

// Safely access title.@value
const cidDescription =
  input &&
  input.title &&
  typeof input.title === 'object' &&
  typeof input.title['@value'] === 'string'
    ? input.title['@value'].trim()
    : "";

// Build normalized output
return [
  {
    json: {
      cid_found: cidDescription !== "",
      cid_description: cidDescription
    }
  }
];

if (!$("Dados CNPJ").first().json.success) {
  return $("Dados CNPJ").first()
 } else {return JSON.parse('{}')}

/**
 * MIA-SADM — QR + HTTP Normalizer (STRICT)
 * INPUT 1 -> httpInput.statusCode
 * INPUT 2 -> qrInput (string JSON or object)
 */

// ================= INPUTS =================
const httpInput = $input.first().json; // HTTP Request
const qrInput   = $('Leitor de QR Code').first().json.stdout; // QR Reader
// ==========================================


// ---------------- Helpers ----------------
function parseJSONSafe(value) {
  if (typeof value === "object") return value;
  if (typeof value === "string") {
    try { return JSON.parse(value); } catch { return null; }
  }
  return null;
}

// ---------------- Output ----------------
const result = {
  qr_exists: false,
  qr_decodable: false,
  qr_target_url: "",
  qr_domain: "",
  qr_bbox: {
    x: 0,
    y: 0,
    width: 0,
    height: 0
  },
  qr_url_status: "error"
};

// ---------------- HTTP (STRICT) ----------------
if (httpInput && httpInput.statusCode === 200) {
  result.qr_url_status = "active";
}

// ---------------- QR (STRICT) ----------------
const qr = parseJSONSafe(qrInput);

if (qr) {
  result.qr_exists = qr.qr_exists === true;
  result.qr_decodable = qr.qr_decodable === true;
  result.qr_target_url = qr.qr_text || "";
  result.qr_domain = qr.qr_domain || "";

  if (qr.qr_bbox) {
    result.qr_bbox = {
      x: qr.qr_bbox.x ?? 0,
      y: qr.qr_bbox.y ?? 0,
      width: qr.qr_bbox.width ?? 0,
      height: qr.qr_bbox.height ?? 0
    };
  }
}

// ---------------- Final rule ----------------
if (!(result.qr_exists && result.qr_decodable && httpInput?.statusCode === 200)) {
  result.qr_url_status = "error";
}

// ---------------- Return ----------------
return [{ json: result }];

var data = $('Output Analise Imagem').first().json;

data.medical_professional.cfm_data = $('output CRM').first().json;

data.issuer_information.cnpj_data = $('Output CNPJ').first().json;

data.medical_classification.cid_oms_data = 
$('Output CID').first().json;

data.qr_validation.qr_code_data = $('Output QRCode').first().json;

return data;

// ============================================
// Recupera dados
// ============================================

// Resposta do HTTP Request (GET + Range bytes=0-0)
const response = $input.first().json;

// URL original enviada no payload
const urlImage = $('Edit Fields').first().json.url_image;

// ============================================
// Valida URL recebida
// ============================================

if (!urlImage) {
  return [
    {
      json: {
        isValid: false,
        status: 400,
        error: "URL da imagem não fornecida",
      },
    },
  ];
}

// ============================================
// Valida Status HTTP
// ============================================

// Sucesso pode ser 200 (OK) ou 206 (Partial Content)
const validStatusCodes = [200, 206];

if (!validStatusCodes.includes(response.statusCode)) {
  return [
    {
      json: {
        isValid: false,
        status: 400,
        url: urlImage,
        statusCode: response.statusCode,
        statusMessage: response.statusMessage,
        error: "URL não acessível (status inválido)",
      },
    },
  ];
}

// ============================================
// Valida Content-Type
// ============================================

const contentType =
  response.headers?.["content-type"] ||
  response.headers?.["Content-Type"] ||
  null;

// Extensões permitidas
const allowedExtensions = ["webp", "jpg", "jpeg", "png", "gif", "bmp"];

// Extrai extensão da URL sem querystring
const urlExtension = (() => {
  try {
    const cleanUrl = urlImage.split("?")[0];
    return cleanUrl.split(".").pop().toLowerCase();
  } catch {
    return "";
  }
})();

// Regras:
// - Content-Type deve começar com image/
// OU extensão deve ser conhecida
const isImageByContentType =
  contentType && contentType.startsWith("image/");

const isImageByExtension =
  allowedExtensions.includes(urlExtension);

// ⚠️ Aqui seu exemplo falharia porque veio application/pdf
if (!isImageByContentType && !isImageByExtension) {
  return [
    {
      json: {
        isValid: false,
        status: 400,
        url: urlImage,
        statusCode: response.statusCode,
        contentType,
        extension: urlExtension || null,
        error:
          "Arquivo acessível, mas não é uma imagem válida (Content-Type incorreto)",
      },
    },
  ];
}

// ============================================
// Gera FILE_PREFIX único
// ============================================

const now = new Date();
const pad = (n, size) => String(n).padStart(size, "0");

const timestamp =
  now.getFullYear() +
  pad(now.getMonth() + 1, 2) +
  pad(now.getDate(), 2) +
  pad(now.getHours(), 2) +
  pad(now.getMinutes(), 2) +
  pad(now.getSeconds(), 2) +
  pad(now.getMilliseconds(), 3);

const FILE_PREFIX = timestamp;

// ============================================
// Resultado FINAL (válido)
// ============================================

return [
  {
    json: {
      isValid: true,
      status: 200,
      url_final: urlImage,
      statusCode: response.statusCode, // 200 ou 206
      contentType,
      extension: urlExtension,
      FILE_PREFIX,
      message: "URL válida e acessível como imagem",
    },
  },
];

/**
 * MIA-SADM — Deterministic Decision & Scoring Engine v2.0.0
 * N8N-ready (drop-in replacement)
 *
 * Core changes (non-negotiables enforced):
 * - Direct approval ("approved_low_risk") ONLY if ALL acceptance premises are satisfied (strict whitelist).
 * - Otherwise: manual verification when needed (including CRM/CFM not validated), or rejected when non-adherent / non-authentic.
 * - Visual subsystem authority: preliminary_recommendation + manipulation flags + image_scores are first-class.
 * - Debug is always emitted when enabled (including early returns).
 */

// =========================================================
// CONFIG
// =========================================================
const ENABLE_RULE_ENGINE_DEBUG = false; // set false in production if you must
const ENGINE_VERSION = "v2.0.0";

// =========================================================
// INPUT
// =========================================================
const inputRaw = $input.first().json;
const input = Array.isArray(inputRaw) ? (inputRaw[0] ?? {}) : (inputRaw ?? {});

// =========================================================
// HELPERS
// =========================================================
const isEmpty = (v) => v === "" || v === undefined || v === null;
const norm = (v) => (isEmpty(v) ? null : v);

function get(obj, path, fallback = null) {
  try {
    const parts = path.split(".");
    let cur = obj;
    for (const p of parts) {
      if (cur == null) return fallback;
      cur = cur[p];
    }
    return cur === undefined ? fallback : cur;
  } catch {
    return fallback;
  }
}

function toISODateFromBR(dateStr) {
  if (!dateStr || typeof dateStr !== "string") return null;
  const m = dateStr.trim().match(/^(\d{2})\/(\d{2})\/(\d{2}|\d{4})$/);
  if (!m) return null;

  const dd = parseInt(m[1], 10);
  const mm = parseInt(m[2], 10);
  let yy = m[3];
  if (yy.length === 2) yy = "20" + yy;
  const yyyy = parseInt(yy, 10);

  if (!(yyyy >= 2000 && yyyy <= 2099)) return null;
  if (!(mm >= 1 && mm <= 12)) return null;
  if (!(dd >= 1 && dd <= 31)) return null;

  const d = new Date(Date.UTC(yyyy, mm - 1, dd));
  if (isNaN(d.getTime())) return null;
  if (d.getUTCFullYear() !== yyyy || d.getUTCMonth() !== (mm - 1) || d.getUTCDate() !== dd) return null;

  return `${String(yyyy).padStart(4, "0")}-${String(mm).padStart(2, "0")}-${String(dd).padStart(2, "0")}`;
}

function todayISODateUTC() {
  const now = new Date();
  const y = now.getUTCFullYear();
  const m = String(now.getUTCMonth() + 1).padStart(2, "0");
  const d = String(now.getUTCDate()).padStart(2, "0");
  return `${y}-${m}-${d}`;
}

function parseISODateToUTC(isoDate) {
  if (!isoDate || typeof isoDate !== "string") return null;
  const m = isoDate.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!m) return null;
  const y = parseInt(m[1], 10);
  const mo = parseInt(m[2], 10);
  const da = parseInt(m[3], 10);
  const d = new Date(Date.UTC(y, mo - 1, da));
  if (isNaN(d.getTime())) return null;
  if (d.getUTCFullYear() !== y || d.getUTCMonth() !== (mo - 1) || d.getUTCDate() !== da) return null;
  return d;
}

function daysBetweenUTC(a, b) {
  // (b - a) in days; a,b are Date
  const ms = b.getTime() - a.getTime();
  return Math.floor(ms / 86400000);
}

function clampScore(n) {
  const x = Number.isFinite(n) ? n : 0;
  return Math.max(0, Math.min(100, x));
}

function anyTrue(obj) {
  if (!obj || typeof obj !== "object") return false;
  return Object.values(obj).some((v) => v === true);
}

function hasQuestionMarks(name) {
  if (!name || typeof name !== "string") return false;
  return name.includes("?") || name.includes("�");
}

function inSet(v, arr) {
  return arr.includes(v);
}

