// =========================================================
// RULE ENGINE EXECUTION
// =========================================================
const gates_failed = [];
const penalties_applied = [];
const bonuses_applied = [];

let forcedDecision = null;     // "rejected_high_risk" | "manual_verification_required" | null
let forcedScore = null;        // number | null
let forcedRationale = null;    // array | null

// ---- Gates first (hard authority) ----
for (const g of RULES.gates) {
  let fail = false;
  try { fail = !!g.fail_if(); } catch { fail = false; }
  if (fail) {
    gates_failed.push({ code: g.code, name: g.name });
    // Highest priority gate wins (first in list)
    if (forcedDecision === null) {
      forcedDecision = g.decision;
      forcedScore = g.base_score;
      forcedRationale = g.rationale();
    }
  }
}

// ---- Scoring if no forced score ----
let score = 0;

if (forcedScore !== null) {
  score = forcedScore;
} else {
  // Penalties
  for (const p of RULES.penalties) {
    if (p.weight) {
      // weighted 0..1 penalty
      let v = null;
      try { v = p.value(); } catch { v = null; }
      if (p.apply_if && p.apply_if() && Number.isFinite(v)) {
        const weight = p.weight;
        const penalty = Math.round((1 - Math.max(0, Math.min(1, v))) * weight);
        if (penalty > 0) {
          penalties_applied.push({ code: p.code, points: penalty, evidence: `${p.code}_value=${v}` });
          score += penalty;
        }
      }
    } else {
      let apply = false;
      try { apply = !!p.apply_if(); } catch { apply = false; }
      if (apply) {
        penalties_applied.push({ code: p.code, points: p.points, evidence: p.evidence ? p.evidence() : "" });
        score += p.points;
      }
    }
  }

  // Bonuses (cap to -40 total)
  let bonusTotal = 0;
  for (const b of RULES.bonuses) {
    let apply = false;
    try { apply = !!b.apply_if(); } catch { apply = false; }
    if (apply) {
      bonuses_applied.push({ code: b.code, points: b.points, evidence: b.evidence ? b.evidence() : "" });
      bonusTotal += b.points;
    }
  }

  if (bonusTotal < RULES.bonus_cap) {
    // clamp bonus total to -40 by scaling
    const scale = RULES.bonus_cap / bonusTotal; // both negative => positive <=1
    let adjustedTotal = 0;
    const adjusted = [];
    for (const b of bonuses_applied) {
      const newPoints = Math.trunc(b.points * scale);
      adjusted.push({ ...b, points: newPoints, evidence: `${b.evidence}|scaled=${scale}` });
      adjustedTotal += newPoints;
    }
    bonuses_applied.length = 0;
    bonuses_applied.push(...adjusted);
    bonusTotal = adjustedTotal;
  }

  score += bonusTotal;

  // Convergence: if visualRisk says medium/high, enforce minimum floors (even without gate)
  if (visualRisk === "medium" && score < 40) score = 40;
  if (visualRisk === "high" && score < 60) score = 60;

  score = clampScore(score);
}

// =========================================================
// RISK LEVEL + DECISION LOGIC
// =========================================================
function riskLevelFromScore(s) {
  if (s <= 24) return "LOW";
  if (s <= 59) return "MEDIUM";
  return "HIGH";
}

let riskLevel = riskLevelFromScore(score);
let manualReviewRequired = (riskLevel === "HIGH");

// Decision default by score
let decisionStatus =
  riskLevel === "LOW" ? "approved_low_risk" :
  riskLevel === "MEDIUM" ? "approved_with_reservations" :
  "manual_verification_required";

// If forced decision (gate), override
if (forcedDecision !== null) {
  decisionStatus = forcedDecision;
  riskLevel = "HIGH";
  manualReviewRequired = true;
}

// =========================================================
// NON-NEGOTIABLE ACCEPTANCE WHITELIST ENFORCEMENT
// =========================================================
// If not eligible for auto approval, DO NOT allow "approved_low_risk".
// Additionally, CRM/CFM not validated => manual review (as you requested).
// CFM validation status MUST be derived exclusively from A5
// No parallel or duplicated logic is allowed
const cfmNotValidated = !crmVerifiedAndValid;

if (decisionStatus === "approved_low_risk") {
  if (!isAutoApprovedEligible) {
    decisionStatus = "manual_verification_required";
    manualReviewRequired = true;
    // ensure score at least medium when whitelist fails hard
    if (score < 25) score = 25;
    riskLevel = riskLevelFromScore(score);
  }
}

// Even if score is low, if CFM not validated, force manual review (your rule)
if (cfmNotValidated) {
  // But do not override an existing rejection gate.
  if (decisionStatus !== "rejected_high_risk") {
    decisionStatus = "manual_verification_required";
    manualReviewRequired = true;
    if (score < 25) score = 25;
    riskLevel = riskLevelFromScore(score);
  }
}

// If not a recognized medical certificate -> reject or manual? You said "não aderente"
if (isMedicalCertificate !== true) {
  decisionStatus = "rejected_high_risk";
  manualReviewRequired = true;
  score = Math.max(score, 85);
  riskLevel = "HIGH";
}

// If preliminary says reject/high but gate did not fire (shouldn't happen), enforce safety
if ((recommendedAction === "reject" || visualRisk === "high") && decisionStatus !== "rejected_high_risk") {
  decisionStatus = "rejected_high_risk";
  manualReviewRequired = true;
  score = Math.max(score, 95);
  riskLevel = "HIGH";
}

// =========================================================
// FORENSIC SUMMARY (strict, no guessing)
// =========================================================
const forensic_summary = {
  visual_manipulation_detected: (manipulationDetected === true) || (digitalManip !== null && digitalManip !== "none"),
  ai_generation_suspected: (aiIndicators !== null && aiIndicators !== "none"),
  visual_quality_resume: anyVisualIssues ? "visual_issues_detected" : "no_visual_issues_detected"
};

// =========================================================
// ELEMENTS CHECKS
// =========================================================
const elements_checks = {
  has_valid_qr_auth: hasValidQrAuth,
  has_strong_stamp_signature_auth: hasStrongStampSignatureAuth,
  has_min_auth: hasMinAuth,
  crm_status_normalized: crmStatusNorm,
  attendance_date_parsed: attendanceDateISO,
  is_future_date: isFutureAttendance
};

// =========================================================
// RATIONALE (1..3 strings, only applied rules)
// =========================================================
const rationaleCandidates = [];

if (forcedRationale && forcedRationale.length) {
  for (const r of forcedRationale) rationaleCandidates.push({ impact: 999, text: r });
} else {
  // penalties and bonuses already applied
  for (const p of penalties_applied) rationaleCandidates.push({ impact: Math.abs(p.points), text: p.code });
  for (const b of bonuses_applied) rationaleCandidates.push({ impact: Math.abs(b.points), text: b.code });

  // whitelist / manual review reasons (only if actually used)
  if (!isAutoApprovedEligible) {
    // add a deterministic reason with high impact (but not more than 1 extra)
    rationaleCandidates.push({ impact: 500, text: "Auto-approval prerequisites not fully satisfied" });
  }
  if (cfmNotValidated) {
    rationaleCandidates.push({ impact: 450, text: "Doctor CFM validation missing or not confirmed" });
  }
}

// Sort & map to human-readable strings
rationaleCandidates.sort((a, b) => b.impact - a.impact);

function rationaleText(codeOrText) {
  // map known codes to concise English (as per your output requirements)
  const m = {
    "Auto-approval prerequisites not fully satisfied": "Auto-approval prerequisites not fully satisfied",
    "Doctor CFM validation missing or not confirmed": "Doctor CFM validation missing or not confirmed",
    "P_IMG_CONSISTENCY": "Low image consistency score",
    "P_IMG_COMPLETENESS": "Low image completeness score",
    "P_IMG_QUALITY": "Low image quality score",
    "P_AGE_OLD_DOCUMENT": "Document date exceeds 30-day window",
    "P_AGE_DEADLINE_EXCEEDED": "Document date exceeds 15-day window",
    "P_AGE_OUT_OF_DEADLINE": "Document date exceeds 7-day window",
    "P_AGE_UNKNOWN": "Unable to determine document age",
    "P_CAPTURE_DIGITAL_NATIVE": "Capture type digital_native increases risk",
    "P_CAPTURE_OTHER": "Unrecognized capture type increases risk",
    "P_MANIPULATION_ANALYSIS_DETECTED": "Manipulation analysis detected",
    "P_DIGITAL_MANIPULATION_INDICATORS": "Digital manipulation indicators detected",
    "P_AI_GENERATION_INDICATORS": "AI generation indicators detected",
    "P_VISUAL_QUALITY_ISSUES": "Visual quality issues impacting validation",
    "P_MISSING_MANDATORY_FIELDS": "Missing mandatory document fields",
    "P_MISSING_MIN_AUTH": "Missing minimum issuer authentication",
    "P_MISSING_DOCTOR_DATA": "Doctor data missing in document elements",
    "P_MISSING_PATIENT_DATA": "Patient data missing in document elements",
    "P_MISSING_DISEASE_DATA": "Disease data missing in document elements",
    "P_CID_INVALID": "CID code provided but not validated",
    "P_PRELIM_MEDIUM_RISK": "Preliminary visual risk is medium",
    "B_VALID_QR": "Valid QR authentication",
    "B_CRM_VERIFIED_MATCHED": "CRM active and matched",
    "B_CID_VALID": "CID code confirmed as valid",
    "B_STAMP_SIGNATURE_VALID": "Stamp and signature both valid"
  };
  return m[codeOrText] || codeOrText;
}

const finalRationale = [];
for (const c of rationaleCandidates) {
  const t = rationaleText(c.text);
  if (!t) continue;
  if (!finalRationale.includes(t)) finalRationale.push(t);
  if (finalRationale.length >= 3) break;
}
if (finalRationale.length === 0) {
  finalRationale.push("Manual verification required");
}

// =========================================================
// OUTPUT (same final JSON structure you are using)
// =========================================================
const out = {
  document_id: null,
  document_type: documentType,
  document: { capture_type: captureType },
  patient: { name: patientName },
  doctor: {
    name: doctorName,
    crm_number: crmNumber,
    crm_uf: crmUF,
    crm_status: crmStatusNorm
  },
  issuer: {
    name: issuerName,
    city: norm(get(input, "issuer_information.city", null)),
    state: norm(get(input, "issuer_information.state", null)),
    cnpj: norm(get(input, "issuer_information.cnpj", null)),
    cnpj_status: "not_verified"
  },
  attendance: {
    type: attendanceType,
    date: attendanceDateISO,
    leave_type: leaveType,
    leave_days: leaveDays,
    leave_hours: leaveHours,
    leave_days_risk: leaveDaysRisk,
    leave_start_date: leaveStartISO,
    leave_end_date: leaveEndISO
  },
  disease: {
    cid_code: cidParent,
    cid_type: cidType,
    cid_valid: cidValid
  },
  forensic_summary,
  elements_checks,
  risk_assessment: {
    risk_score: clampScore(score),
    risk_level: riskLevel,
    manual_review_required: manualReviewRequired
  },
  decision: {
    status: decisionStatus,
    rationale: finalRationale
  }
};

// =========================================================
// DEBUG (always present when enabled; includes acceptance checklist)
// =========================================================
if (ENABLE_RULE_ENGINE_DEBUG) {
  out._rule_engine_debug = {
    engine_version: ENGINE_VERSION,
    rules_version: RULES.version,
    acceptance_checklist: acceptanceChecklist,
    is_auto_approved_eligible: isAutoApprovedEligible,
    cfm_not_validated: cfmNotValidated,
    gates_failed,
    penalties_applied,
    bonuses_applied,
    key_signals: {
      is_medical_certificate: isMedicalCertificate,
      capture_type: captureType,
      ocr_confidence_avg: ocrConfidence,
      patient_name_ok: patientNameOk,
      doctor_fields_ok: doctorFieldsOkForAuto,
      crm_verified_and_valid: crmVerifiedAndValid,
      issuer_ok: issuerOkForAuto,
      attendance_type_ok: attendanceTypeOk,
      attendance_date_iso: attendanceDateISO,
      attendance_age_days: attendanceAgeDays,
      within_30_days: within30Days,
      leave_present: leavePresent,
      leave_dates_consistent: leaveDatesConsistent,
      leave_risk_ok_for_auto: leaveRiskOkForAuto,
      cid_ok_for_auto: cidOkForAuto,
      elements_ok_for_auto: elementsOkForAuto,
      no_manipulation_ok_for_auto: noManipulationOkForAuto,
      qr_present_but_invalid: qrPresentButInvalid,
      image_scores: imageScores,
      image_scores_ok_for_auto: imageScoresOkForAuto,
      preliminary: { visual_risk: visualRisk, recommended_action: recommendedAction, reason_code: visualReasonCode }
    }
  };
}

return [{ json: out }];
